#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
int balanceStack(vector<int>& elements) {
    stack<int> stk;
    for (int i = 0; i < elements.size(); ++i) {
        if (elements[i] >= stk.empty() ? 0 : stk.top()) {
            stk.push(elements[i]);
        } else {
            while (!stk.empty() && stk.top() > elements[i]) {
                stk.pop();
            }
            stk.push(elements[i]);
        }
    }
    return elements.size() - stk.size();
}
};

int main() {
    Solution sol;
    int n;
    cin >> n;
    vector<int> elements(n);
    for (int i = 0; i < n; ++i) {
        cin >> elements[i];
    }
    cout << sol.balanceStack(elements) << endl;
    return 0;
}
